#!/usr/bin/env python3
import argparse
import shutil
import subprocess
import sys
from pathlib import Path


def ensure_fastzipx_available() -> None:
    if shutil.which("fastzipx") is None:
        print("Error: 'fastzipx' is not installed or not found in PATH.", file=sys.stderr)
        sys.exit(127)


def compress_path(path: Path, quiet: bool = False) -> int:
    cmd = ["fastzipx", "--compress-max", "--ai-mode", str(path)]
    if not quiet:
        print(f"[fastzipx] Compressing: {path}")
    try:
        proc = subprocess.run(cmd, check=False)
        if proc.returncode != 0:
            if not quiet:
                print(f"[fastzipx] Failed: {path} (exit code {proc.returncode})", file=sys.stderr)
        else:
            if not quiet:
                print(f"[fastzipx] Done: {path}")
        return proc.returncode
    except FileNotFoundError:
        # Shouldn't happen due to ensure_fastzipx_available, but keep for safety
        print("Error: 'fastzipx' not found during execution.", file=sys.stderr)
        return 127
    except Exception as e:
        print(f"Error: Exception while compressing {path}: {e}", file=sys.stderr)
        return 1


def main() -> None:
    parser = argparse.ArgumentParser(
        description="Compress files/directories using 'fastzipx' with --compress-max --ai-mode."
    )
    parser.add_argument(
        "paths",
        nargs="+",
        help="Files or directories to compress."
    )
    parser.add_argument(
        "--continue-on-error",
        action="store_true",
        help="Continue processing remaining paths if one fails."
    )
    parser.add_argument(
        "-q", "--quiet",
        action="store_true",
        help="Reduce output verbosity."
    )
    args = parser.parse_args()

    ensure_fastzipx_available()

    overall_rc = 0
    for raw in args.paths:
        p = Path(raw)
        if not p.exists():
            print(f"Error: Path does not exist: {p}", file=sys.stderr)
            overall_rc = 1
            if not args.continue_on_error:
                sys.exit(overall_rc)
            continue

        rc = compress_path(p, quiet=args.quiet)
        if rc != 0:
            overall_rc = rc
            if not args.continue_on_error:
                sys.exit(overall_rc)

    sys.exit(overall_rc)


if __name__ == "__main__":
    main()

